import{_ as a,o as e,c as r,a2 as o}from"./chunks/framework.BWuWLRhz.js";const p=JSON.parse('{"title":"快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md","lastUpdated":1783252730000}'),l={name:"guide/getting-started.md"};function i(d,t,s,n,h,c){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><p>从零开始使用自由港机场，只需要三步：<strong>注册 → 购买 → 导入</strong>。全程约 5 分钟。</p><h2 id="第一步-注册账号" tabindex="-1">第一步：注册账号 <a class="header-anchor" href="#第一步-注册账号" aria-label="Permalink to &quot;第一步：注册账号&quot;">​</a></h2><ol><li>打开官网 <a href="https://freedomport.cc" target="_blank" rel="noreferrer">freedomport.cc</a>，点击右上角 <strong>账号设置</strong> 或直接进入<a href="https://freedomport.cc/#/auth" target="_blank" rel="noreferrer">登录页</a></li><li>切换到 <strong>注册</strong> 标签，填写邮箱和密码</li><li>如果朋友给了你邀请码，在注册页填入（也可以通过邀请链接打开，会自动填好）</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>也可以<strong>先购买后注册</strong>：在<a href="https://freedomport.cc/#/purchasing" target="_blank" rel="noreferrer">购买页</a>直接以游客身份下单，支付成功后系统会自动创建账号，并把登录信息发送到你填写的邮箱。</p></div><h2 id="第二步-购买套餐" tabindex="-1">第二步：购买套餐 <a class="header-anchor" href="#第二步-购买套餐" aria-label="Permalink to &quot;第二步：购买套餐&quot;">​</a></h2><ol><li>进入<a href="https://freedomport.cc/#/purchasing" target="_blank" rel="noreferrer">购买页</a>，或登录后在会员中心点击 <strong>购买订阅</strong></li><li>根据你的需求选择套餐（每张套餐卡列出了流量、设备数、线路覆盖和适合人群）</li><li>选择付款周期，确认订单后选择支付方式完成付款</li><li>支付成功后订阅自动开通，订单状态会同步到会员中心</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>建议以<strong>月付为主</strong>，先确认节点适合你的网络环境。退款条件见<a href="./../policy/terms">使用规范与退款政策</a>。</p></div><h2 id="第三步-导入客户端" tabindex="-1">第三步：导入客户端 <a class="header-anchor" href="#第三步-导入客户端" aria-label="Permalink to &quot;第三步：导入客户端&quot;">​</a></h2><ol><li>登录<a href="https://freedomport.cc/#/dashboard" target="_blank" rel="noreferrer">会员中心</a>，在 <strong>订阅链接</strong> 卡片复制你的专属订阅链接（或直接扫二维码 / 点客户端图标一键导入）</li><li>按你的设备打开对应教程，几分钟完成配置：</li></ol><table tabindex="0"><thead><tr><th>设备</th><th>推荐客户端</th><th>备选</th></tr></thead><tbody><tr><td>Windows</td><td><a href="./../clients/windows/clash-verge">Clash Verge Rev</a></td><td><a href="./../clients/windows/v2rayn">v2rayN</a></td></tr><tr><td>macOS</td><td><a href="./../clients/macos/clash-verge">Clash Verge Rev</a></td><td>—</td></tr><tr><td>iOS / iPadOS</td><td><a href="./../clients/ios/clash-mi">Clash Mi</a></td><td><a href="./../clients/ios/shadowrocket">Shadowrocket</a></td></tr><tr><td>Android</td><td><a href="./../clients/android/clash-meta">Clash Meta for Android</a></td><td><a href="./../clients/android/v2rayng">v2rayNG</a></td></tr><tr><td>路由器</td><td><a href="./../clients/others/router">OpenClash 等</a></td><td><a href="./../clients/others/README">Linux / Apple TV</a></td></tr></tbody></table><p>全部下载入口见<a href="./../download">客户端下载</a>。</p><ol start="3"><li>客户端里选择节点并开启连接，打开浏览器验证是否可以访问外网</li></ol><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>想了解订阅链接的更多用法（更新、重置、二维码）→ <a href="./subscription">订阅链接使用说明</a></li><li>连不上或没有节点 → <a href="./faq">常见问题 FAQ</a></li></ul>',15)])])}const g=a(l,[["render",i]]);export{p as __pageData,g as default};
